Building Production RAG Systems with PostgreSQL: Complete Implementation Guide Most RAG (Retrieval-Augmented Generation) systems fail in production for predictable technical reasons: poor retrieval quality, lack of source attribution, and inability to handle real-world query variations. This guide shows you how to build a production-ready RAG system that actually works. Production RAG failures stem from three core technical problems: 1. Pure Vector Search Limitations 2. No Source Attribution 3. Single Search Strategy Our architecture uses PostgreSQL with the pgvector extension to handle both vector and traditional search in a single, reliable database: ┌─────────────────┐ ┌──────────────────┐ ┌─────────────────┐ │ Document │───▶│ PostgreSQL │───▶│ Answer │ │ Processing │ │ + pgvector │ │ Generation │ └─────────────────┘ └──────────────────┘ └─────────────────┘ -- Full documents with complete context CREATE TABLE documents ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT NOT NULL, content TEXT NOT NULL, url TEXT UNIQUE NOT NULL, category TEXT NOT NULL, last_updated TIMESTAMP DEFAULT NOW(), content_hash TEXT NOT NULL, embedding vector(1536), metadata JSONB DEFAULT '{}' ); -- Document chunks for precise retrieval CREATE TABLE document_chunks ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), document_id UUID REFERENCES documents(id) ON DELETE CASCADE, chunk_index INTEGER NOT NULL, content TEXT NOT NULL, embedding vector(1536), token_count INTEGER NOT NULL, section_title TEXT, start_position INTEGER, end_position INTEGER, metadata JSONB DEFAULT '{}', UNIQUE(document_id, chunk_index) ); Create essential indexes: -- Full-text search for keyword matching CREATE INDEX idx_chunks_fts ON document_chunks USING gin (to_tsvector('english', content)); -- Vector search for semantic matching CREATE INDEX idx_chunks_embedding ON document_chunks USING hnsw (embedding vector_l2_ops) WITH (m = 16, ef_construction = 64); The core of our system a function that combines semantic and keyword search: CREATE OR REPLACE FUNCTION hybrid_search( query_text TEXT, query_embedding vector(1536), limit_count INTEGER DEFAULT 10, semantic_weight FLOAT DEFAULT 0.6, keyword_weight FLOAT DEFAULT 0.4 ) RETURNS TABLE ( chunk_id UUID, content TEXT, semantic_score DOUBLE PRECISION, keyword_score DOUBLE PRECISION, combined_score DOUBLE PRECISION, document_title TEXT, document_url TEXT ) AS $$ BEGIN RETURN QUERY WITH semantic_results AS ( SELECT c.id as chunk_id, c.content, (1 - (c.embedding query_embedding))::DOUBLE PRECISION as semantic_score, d.title as document_title, d.url as document_url FROM document_chunks c JOIN documents d ON c.document_id = d.id ORDER BY c.embedding query_embedding LIMIT limit_count * 3 ), keyword_results AS ( SELECT c.id as chunk_id, ts_rank_cd(to_tsvector('english', c.content), plainto_tsquery('english', query_text))::DOUBLE PRECISION as keyword_score FROM document_chunks c WHERE to_tsvector('english', c.content) @@ plainto_tsquery('english', query_text) ) SELECT s.chunk_id, s.content, s.semantic_score, COALESCE(k.keyword_score, 0.0) as keyword_score, (semantic_weight * s.semantic_score + keyword_weight * COALESCE(k.keyword_score, 0.0))::DOUBLE PRECISION as combined_score, s.document_title, s.document_url FROM semantic_results s LEFT JOIN keyword_results k ON s.chunk_id = k.chunk_id WHERE (semantic_weight * s.semantic_score + keyword_weight * COALESCE(k.keyword_score, 0.0)) > 0.3 ORDER BY combined_score DESC LIMIT limit_count; END; $$ LANGUAGE plpgsql; Smart chunking that preserves context: import asyncpg import openai from typing import List, Dict import re from dataclasses import dataclass @dataclass class DocumentChunk: content: str section_title: str chunk_index: int token_count: int class DocumentProcessor: def __init__(self, db_url: str, openai_api_key: str): self.db_url = db_url self.client = openai.AsyncOpenAI(api_key=openai_api_key) def _create_smart_chunks(self, content: str, max_tokens: int = 512) -> List[DocumentChunk]: 